from __future__ import (
    annotations,  # noqa: D100  import re from collections.abc import Mapping from typing import TYPE_CHECKING, Any, cast  if TYPE_CHECKING:     from app.connectors.slack.slack_channel import SlackChannel  from app.connectors.slack.ui.modal_builder import ModalBuilder from app.core.logging import get_logger from app.db.records import IntegrationRecord from app.domains.messaging.slack.service import SlackMessagingService from app.utils import action_ids from app.utils.constants import (     SLACK_ERROR_ICON,     SLACK_SUCCESS_ICON, )  from .base import (     InteractionHandler,     UnifiedContext,     interaction_handler, )  logger = get_logger("ticket_modal_handlers")   class TicketModalHandlers(InteractionHandler):     async def _handle_ticket_submission(  # noqa: PLR0915         self,         integration: IntegrationRecord,         properties: dict[str, Any],         association: str | None,         messaging_service: SlackMessagingService,         context: UnifiedContext,         user_id: str,     ) -> None:         """Handles complex ticket creation, channel         provisioning, and Slack onboarding.         """         try:             subject = properties.get("subject", "Support Ticket")             hs_associations = []              # Bridging: Resolve Slack user as the ticket contact BEFORE creation             try:                 logger.info(                     "Attempting to resolve Slack user %s for atomic ticket bridging",                     user_id,                 )                 channel_inst = await messaging_service.get_slack_channel()                 slack_client = cast("SlackChannel", channel_inst).get_slack_client()                 user_info = await slack_client.users_info(user=user_id)                  if user_info.get("ok"):                     profile = user_info.get("user", {}).get("profile", {})                     email = profile.get("email")                     name = profile.get("real_name")                      if email:                         contact_id = await self.crm.find_or_create_contact_by_email(                             integration.workspace_id, email, name                         )                         hs_associations.append(                             {                                 "to": {"id": contact_id},                                 "types": [                                     {                                         "associationCategory": "HUBSPOT_DEFINED",                                         "associationTypeId": 16,  # ticket_to_contact                                     }                                 ],                             }                         )                         logger.info(                             "Queued atomic association: contact_id=%s for email=%s",                             contact_id,                             email,                         )                     else:                         logger.warning(                             "No email found for Slack user %s (scope issue?)", user_id                         )             except Exception as bridge_err:                 logger.warning(                     "Failed to prepare ticket-contact bridge: %s", bridge_err                 )              # Add existing association (e.g. from a Company/Deal card)             if association:                 assoc_type, assoc_id = association.split(":")                 type_id = (                     18 if assoc_type == "company" else 28                 )  # ticket_to_company / ticket_to_deal                 hs_associations.append(                     {                         "to": {"id": assoc_id},                         "types": [                             {                                 "associationCategory": "HUBSPOT_DEFINED",                                 "associationTypeId": type_id,                             }                         ],                     }                 )              # Create ticket with ALL associations atomically             ticket = await self.crm.create_ticket(                 integration.workspace_id, properties, associations=hs_associations             )             ticket_id = ticket["id"]             logger.info(                 "SUCCESS: Created ticket %s with %d associations",                 ticket_id,                 len(hs_associations),             )             channel_inst = await messaging_service.get_slack_channel()             slack_client = cast("SlackChannel", channel_inst).get_slack_client()             raw_name = f"ticket-{ticket_id}-{subject.lower()}"             channel_name = re.sub("[^a-z0-9-]", "-", raw_name)[:80].strip("-")             create_resp = await slack_client.conversations_create(                 name=channel_name, is_private=True             )             if not create_resp.get("ok"):                 logger.error(                     "Failed to create Slack channel: %s", create_resp.get("error")                 )                 await slack_client.chat_postMessage(                     channel=user_id,                     text=(                         f"{SLACK_SUCCESS_ICON} Created HubSpot ticket #{ticket_id}, "                         f"but failed to create a private channel: "                         f"`{create_resp.get('error')}`"                     ),                 )                 return             new_channel_id = create_resp["channel"]["id"]             logger.info("Provisioned Slack channel: %s", new_channel_id)              # Store channel-to-ticket mapping for sync             from app.db.records import ThreadMappingRecord              await self.integration_service.storage.save_thread_mapping(                 ThreadMappingRecord(                     workspace_id=integration.workspace_id,                     object_type="ticket",                     object_id=ticket_id,                     channel_id=new_channel_id,                     thread_ts="CHANNEL_ROOT",                 )             )             await slack_client.conversations_invite(                 channel=new_channel_id, users=[user_id]             )             builder = ModalBuilder()             control_panel_blocks = builder.build_ticket_control_panel(                 ticket_id, subject             )             await slack_client.chat_postMessage(                 channel=new_channel_id,                 text=f"≡ƒÄ½ Ticket #{ticket_id} created!",                 blocks=control_panel_blocks,             )             success_msg = (                 f"{SLACK_SUCCESS_ICON} Ticket created! Join your support channel: "                 f"<#{new_channel_id}>"             )             await slack_client.chat_postMessage(channel=user_id, text=success_msg)         except Exception as exc:             logger.exception("Ticket submission failed")             if user_id:                 try:                     client = await self.integration_service.get_slack_client(                         integration                     )                     await client.chat_postMessage(                         channel=user_id,                         text=f"{SLACK_ERROR_ICON} Failed to create ticket: {str(exc)}",                     )                 except Exception:                     pass      @interaction_handler(action_ids.SUPPORT_TICKET_SUBMISSION)     async def _handle_support_ticket_submission(         self,         *,         payload: Mapping[str, Any],         integration: IntegrationRecord,         messaging_service: SlackMessagingService,         context: UnifiedContext,         **kwargs: Any,     ) -> None:         """Processes the support ticket modal submission and creates a ticket         in the developer's support portal.         """         view = payload.get("view", {})         user_id = context.user_id          if not user_id:             logger.error("Missing user_id in support ticket submission")             return          # 1. Extract form values         from app.utils.parsers import extract_state_values          properties = extract_state_values(view)         hs_associations = None          # 2. Add user context from Slack         real_name = "Unknown Slack User"         email = "no-email@slack.com"         try:             slack_client = await self.integration_service.get_slack_client(integration)             user_info = await slack_client.users_info(user=user_id)              if user_info.get("ok"):                 user = user_info.get("user", {})                 profile = user.get("profile", {})                 real_name = profile.get("real_name") or user.get(                     "name", "Unknown Slack User"                 )  # noqa: E501                 email = profile.get("email") or "no-email@slack.com"                  # Append user details to description                 current_description = properties.get("content", "")                 properties["content"] = (                     f"{current_description}\n\n"                     f"--- Requester Context ---\n"                     f"Slack Name: {real_name}\n"                     f"Slack Email: {email}\n"                     f"Slack User ID: {user_id}\n"                     f"Workspace ID: {integration.workspace_id}"                 )                 # Map internal properties                 properties["hs_ticket_priority"] = properties.get(                     "hs_ticket_priority", "medium"                 ).upper()              # 4. Create HubSpot Support Ticket directly in REHA portal             try:                 support_client = await self.crm.get_support_client()                  # 4.1 Sync Contact to Support Portal (Search by email)                 contact_results = await support_client.search_objects(                     "contacts", query_string=email, properties=["email"]                 )                  if contact_results:                     support_contact_id = contact_results[0]["id"]                 else:                     name_parts = real_name.split(" ", 1)                     new_contact = await support_client.create_object(                         "contacts",                         {                             "email": email,                             "firstname": name_parts[0],                             "lastname": name_parts[1] if len(name_parts) > 1 else "",                             "hs_lead_status": "NEW",                         },                     )                     support_contact_id = new_contact["id"]                  # 4.2 Create Support Ticket                 ticket_props = {                     "subject": f"Slack Support: {properties.get('subject', 'No Subject')}",                     "content": properties.get("content", ""),                     "hs_pipeline": "0",  # Support Pipeline                     "hs_pipeline_stage": "1",  # New                     "hs_ticket_priority": properties.get(                         "hs_ticket_priority", "MEDIUM"                     ).upper(),                     "hs_ticket_category": properties.get(                         "hs_ticket_category", "GENERAL"                     ).upper(),                 }                  # Atomic association to the requester contact                 hs_associations = [                     {                         "to": {"id": support_contact_id},                         "types": [                             {                                 "associationCategory": "HUBSPOT_DEFINED",                                 "associationTypeId": 16,  # ticket_to_contact                             }                         ],                     }                 ]                  ticket = await support_client.create_object(                     "tickets", ticket_props, associations=hs_associations                 )                 ticket_id = ticket["id"]                 logger.info("Created support ticket #%s in REHA portal", ticket_id)                  # 5. Notify user of success                 await slack_client.chat_postMessage(                     channel=user_id,                     text=(                         f"{SLACK_SUCCESS_ICON} *Support Ticket Created!* (Ref: #{ticket_id})\n"                         "Your request has been routed directly to our HubSpot Helpdesk. "                         "One of our engineers will reach out to you shortly."                     ),                 )             except Exception as hs_exc:                 logger.error(                     "Failed to create native HubSpot support ticket: %s", hs_exc                 )                 # Fallback to Email if HubSpot fails (Legacy Path)                 from app.domains.common.email_service import EmailService                  email_service = EmailService()                 await email_service.send_support_email(                     subject=f"Slack Support [FALLBACK]: {properties.get('subject', 'No Subject')}",                     content=properties.get("content", ""),                     from_email=email,                     from_name=real_name,                     to_email="support@rehaapps.com",                     metadata={                         "Slack User ID": user_id,                         "Workspace ID": integration.workspace_id,                         "Priority": properties.get("hs_ticket_priority", "MEDIUM"),                     },                 )                  await slack_client.chat_postMessage(                     channel=user_id,                     text=(                         f"{SLACK_SUCCESS_ICON} *Support Request Sent!* \n"                         "Your message has been delivered to our support team. "                         "We'll review it and get back to you via email as soon as possible."                     ),                 )         except Exception as exc:             logger.exception("Support ticket creation failed")             try:                 slack_client = await self.integration_service.get_slack_client(                     integration                 )  # noqa: E501                 await slack_client.chat_postMessage(                     channel=user_id,                     text=f"{SLACK_ERROR_ICON} *Submission Failed:* {str(exc)}",                 )             except Exception:                 pass
)
